
#include "svg_helper.h"
int main(){string stem="07_insertion_sort",title="07 Insertion Sort"; vector<vector<int>> frames={{5,3,8,1,4,7},{3,5,8,1,4,7},{3,5,8,1,4,7},{1,3,5,8,4,7},{1,3,5,8,4,7},{1,3,4,5,8,7},{1,3,4,5,7,8},{1,3,4,5,7,8}}; vector<int> key={1,1,3,3,4,4,5,5}; vector<string> f={"sorted prefix on left","take key from first unsorted cell","shift larger items right","insert key into gap"}; for(int k=0;k<frames.size();++k){int W=1140,H=680; set<int> done, hot={key[k]}; for(int i=0;i<min((int)frames[k].size(), key[k]); ++i) done.insert(i); string s=startSVG(W,H,title,"Step "+to_string(k+1)+" / "+to_string(frames.size())+" - insert key into sorted prefix"); s+=box(50,120,610,400,"#fff","#bfd3e6"); s+=T(90,155,"Insertion sort: key is lifted, larger values shift right",17,"#123","700"); s+=arr(frames[k],90,200,hot,done); int x=90+key[k]*58+29; s+=arrow(x,185,x,150,"#d92d27",4); s+=labelBox(x-28,137,"key", "#fee2e2", "#ef4444"); for(int i=max(0,key[k]-2); i<key[k]; ++i) s+=arrow(90+i*58+45,310,90+(i+1)*58+25,310,"#f97316",3); s+=box(90,375,500,70,"#f8fafc","#94a3b8"); s+=T(110,405,"Prefix remains sorted after each insertion",16,"#166534","700"); s+=T(110,430,"Animation is not generic bars: it shows key extraction + shifting gap.",14,"#334155"); s+=sidebar(k+1,frames.size(),f)+footer(W,H,stem+".cpp"); stringstream p; p<<"output/"<<stem<<"_steps/step_"<<setw(2)<<setfill('0')<<k+1<<".svg"; writeFile(p.str(),s+endSVG());}}
